/// and its lines (<c>InventJournalTrans</c>) based on
/// an Operation (<c>ETGSPAINPurchOperationTable</c>) (Contract) for the ETGSPAIN model.
/// </summary>
[DataContractAttribute]
class ETGSPAINPurchCreateInventJournalTableContract
{
    container recordCon;

}

Method.Source:
/// <summary>
/// parm method for the <c>container</c> of records <c>recordCon</c>.
/// </summary>
/// <param name="_recordCon"><c>container</c> of records <c>recordCon</c></param>
/// <returns><c>container</c> of records <c>recordCon</c></returns>
[DataMemberAttribute, SysOperationControlVisibilityAttribute(false)]
public container parmRecordCon(container _recordCon = recordCon)
{
    recordCon = _recordCon;

    return recordCon;
}
